var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"이 땅의 첫 번째 정착자들은 실로 현명하였다.","JPN":"この地の最初の定着者は実に賢明であった。","ENG":"The First Settlers of these lands were truly wise.","TWN":"這片土地上的第一批定居者實在明智。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"사슴의 눈에 담긴 세상을 들여다보고 풀과 나무가 속삭이는 충고에 귀 기울일 줄 알았다.","JPN":"鹿の目に映った世界を覗き込み、草と木がささやく忠告に耳を澄ました。","ENG":"They knew how to see the world through the eyes of a deer and listen to the advice whispered by the grass and trees.","TWN":"他們懂得窺視鹿眼中的世界，會傾聽草木和樹木私語的忠告。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"사제이자 철학자였던 그들은 인간의 내면을 갉아먹으며 성장하는 위협을 일찍부터 알아챘다.","JPN":"司祭であり、哲学者でもあった彼らは人間の内面を蝕みながら成長する脅威を早い段階で察知した。","ENG":"As priests and philosophers, they recognized the creeping threat to humanity early on.","TWN":"既是司祭又是哲學家的他們，很早就察覺到腐蝕人類內心，並且阻礙成長的威脅。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"그렇기에 우리는 세상과 단절하고 높은 성벽을 쌓아 올렸다.","JPN":"だからこそ我らは世界と断絶し、高い城壁を積み上げた。","ENG":"So they erected the tallest of walls and cut themselves off from the rest of the world...","TWN":"於是，我們與世隔絕，築起一座高牆。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"오래 전, 첫 번째 정착자들이 화톳불 속에서 목격했던 마지막 날을 예비하기 위해.","JPN":"かつて最初の定着者がかがり火の中で目撃した最後の日に備えるために。","ENG":"To prevent the end of days that they had witnessed long ago through the bonfire.","TWN":"很久以前，為預備第一批定居者在篝火中目睹到末日。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"subtitle","speaker":null,"text":{"KOREA":"대정화전쟁. 침식의 날 D+12","JPN":"大浄化戦争。侵食の日 D+12","ENG":"The Great Purification War. Day of Corruption, D+12","TWN":"大淨化戰爭，侵蝕日D+12"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"subtitle","speaker":null,"text":{"KOREA":"노르드나빅 왕국, 수도 아발론 방위선.","JPN":"ノルドナビック王国、首都アバロンの防衛線。","ENG":"Defense line of Avalon, the capital of the Nordnavik kingdom.","TWN":"諾爾德萊比王國，首都阿瓦隆防線"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"총사대장님! 괴물들이 장벽을 넘어 쏟아져 들어오고 있습니다!","JPN":"銃士隊長！　やつらが障壁を越えて押し寄せて来ています！","ENG":"Sir! Those monsters have scaled our walls and are pouring in!","TWN":"隊長！怪物們正越過城牆衝過來！"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"막아라!","JPN":"阻止しろ！","ENG":"Stop them!","TWN":"攔住！"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"저것들이 들어오게 내버려 두지 마!","JPN":"やつらの侵入を許すな！","ENG":"Don't let them get any closer!","TWN":"別讓他們進來！"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"데이빗, 파형 분석은 어떻게 되어가고 있나?","JPN":"デイビッド、波形の分析はどうなっている？","ENG":"David! How's the ray analysis going?","TWN":"大衛，波形分析進展如何?"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"너무 불규칙적입니다. 침식현상이 허공에서 마구잡이로 발생하고 있습니다.","JPN":"あまりにも不規則です。侵食現象が虚空からランダムに発生しています。","ENG":"It's too irregular. The Counterside Effect is happening all over the place!","TWN":"非常不規律，侵蝕現象在虛空中不平凡地發生。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"저 괴물들이 아무 저항 없이 장벽을 넘었다는 건, 낙원문에 문제가 생겼다는 뜻인가?","JPN":"あの化け物どもが何の妨害もなく障壁を越えたということは、楽園の門に問題が生じたということか？","ENG":"Those monsters were able to climb our walls without any resistance. Did something happen to Avalon's Gate?","TWN":"那些怪物盲目地翻過城牆，難道是樂園門出什麼問題？"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"네. 그것 말고는 다른 가능성이 떠오르지 않습니다.","JPN":"はい。それ以外の可能性は考えられません。","ENG":"Perhaps. There's no other explanation.","TWN":"是的。除此之外，我想不出其他的可能性。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"총사대장님! 왕성으로부터 연락입니다!","JPN":"銃士隊長！　王城からの連絡です！","ENG":"Sir! A call from the royal castle has just arrived!","TWN":"隊長！有來自王城的聯繫！"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"연락? 설마 내성이 공격받은 건가?","JPN":"連絡？　まさか内城が攻撃を受けたのか？","ENG":"A call? Is the castle under attack?!","TWN":"聯繫？難道是城裡受到攻擊嗎？"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"다행히 그건 아닌 것 같군요. 이건 전하의 직통 라인입니다.","JPN":"幸い、そうではないようです。これは殿下の直通ラインです。","ENG":"Fortunately, that does not appear to be the case. It's coming from the king's direct hotline.","TWN":"幸好不是，這是殿下專屬的通訊。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"바로 연결해 주게.","JPN":"今すぐ繋げてくれ。","ENG":"Put me through.","TWN":"馬上接通。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"열쇠를 회수하라니요? 침식을 막아 주던 낙원문을 포기한다는 겁니까?","JPN":"鍵を回収しろですと？　侵食を塞いでいた楽園の門を放棄するということですか？","ENG":"Retrieve the Key? Are we giving up on defending Avalon's Gate, which has kept us safe from the Corruption?","TWN":"收回鑰匙？意思是要放抵擋侵蝕的樂園門嗎？"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"그래. 낙원문의 힘은 한계에 달했다. 더 이상 버티다간 열쇠까지 파괴될지도 모른다더군.","JPN":"そうだ。楽園の門の力はもう限界だ。このままでは鍵まで破壊される危険があるらしい。","ENG":"Yes. The Gate has reached its maximum capacity. He says that if we continue to hold out here, the Key might get destroyed.","TWN":"對，樂園門的力量已經達到極限，再硬撐下去，說不定連鑰匙毀掉。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"폐하께서는 새로운 낙원문을 세워 그곳에서 항쟁을 이어가실 생각이다.","JPN":"陛下は新しい楽園の門を建て、そこで抗争を継続なさるおつもりだ。","ENG":"His Majesty intends to construct a new Avalon's Gate elsewhere and continue the fight there.","TWN":"陛下要建一個新的樂園門，打算在那裡繼續抗爭。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"게다가…… 열쇠를 노리는 존재가 있다는 모양이야.","JPN":"それに……どうやら鍵を狙っている存在がいるらしい。","ENG":"Also... it appears that someone or something is after the Key.","TWN":"再加上… 好像有人在覬覦鑰匙。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"열쇠를 말입니까?","JPN":"鍵をですか？","ENG":"You mean steal the Key?","TWN":"你說鑰匙嗎？"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"대체 누가 그런 위험천만한 짓을……. 설마 왕위를 탐내는 자들입니까?","JPN":"一体誰がそんな危ない真似を……まさか王位を狙う者ですか？","ENG":"Who would dare to risk something like that...? Do they desire to sit on the throne?","TWN":"到底是誰做這麼危險的事…難道是想貪圖王位嗎？"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"데이빗. 분열을 야기하는 언행은 삼가도록.","JPN":"デイビッド。分裂を引き起こす言動は慎め。","ENG":"David, please refrain from saying or doing anything that might cause a turmoil.","TWN":"大衛，請注意發言，切勿引起不必要的紛爭。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"그럼 노르드나빅의 어느 누가 열쇠를 노리겠습니까? 지성도 없는 침식체들이요?","JPN":"それではノルドナビックのいったい誰が鍵を狙うというのですか？　知性もない侵食体ではないでしょう。","ENG":"Then who else in Nordnavik would go after the Key? Those mindless C.O.s?","TWN":"那麼諾爾德萊比的誰會覬覦鑰匙呢？沒有思想的侵蝕體嗎?"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"우리는 군명에 따라 열쇠를 운반하면 돼. 내가 지금 해 줄 수 있는 대답은 그것뿐이다.","JPN":"我々は軍の命令に従い、鍵を運べばいい。今私が答えられるのはそれだけだ。","ENG":"We have orders to relocate the Key. That's all I can say to you right now.","TWN":"我們只需要按照軍令遷移鑰匙，這是我現在唯一能回答你的。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"……알겠습니다. 어디로 가야 합니까?","JPN":"……了解しました。どこへ向かえばいいのですか？","ENG":"...Yes, sir. Where are we headed?","TWN":"……遵命，但要遷往哪裡呢？"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"남쪽 끝. 디어루트 외성이다.","JPN":"南の端。ディアルート外郭だ。","ENG":"To the southernmost outer castle, Deer Root.","TWN":"在南方，迪魯特外城。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"우리는 괴물에 맞설 무기를 만들고, 성자들을 소집해 항전의 기반을 다졌다.","JPN":"我々は化け物に立ち向かう武器を作り、聖者を招集して抗戦の基礎を築いた。","ENG":"We laid out the groundwork to fight against these monsters by forging weapons and summoning the Helgons.","TWN":"我們製造出對抗怪物的武器，並召集聖者奠定抗戰基礎。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"나라의 중심에는 낙원문이라 불리는 탑을 세워 열쇠를 안치해 불온한 힘이 닿을 수 없게 하였다.","JPN":"国の中心には楽園の門と呼ばれる塔を建てて鍵を安置し、不穏な力が届かないようにした。","ENG":"We erected Avalon's Gate, a tower in the center of the kingdom, where The Key was placed to protect the kingdom from the evil forces.","TWN":"在國家的中心打造一座稱之為樂園門的塔，並將鑰匙安置在內，使不安定的力量無法觸及。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 정착자들이 예견했던 그 날, 균열을 찢고 도래한 붉은 침식의 기운이 온 세상을 뒤덮었다.","JPN":"そして定着者が予見したその日、亀裂を裂いて到来した赤い侵食の気が全世界を覆い尽くした。","ENG":"And, just as the Settlers predicted, the crimson wave of Corruption ripped through the cracks and covered the entire world.","TWN":"而在定居者預見的那一天，穿越裂縫而來的紅色侵蝕氣息籠罩全世界。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 우리는 굳건한 벽과 결사의 항쟁으로 우리의 터전을 지킬 수 있었다.","JPN":"だが、我々は固い壁と決死の抗争で我々の地を守ることができた。","ENG":"Nonetheless, with our strong walls and the willingness to fight to the death, we were able to protect our homeland.","TWN":"不過，我們可以憑藉堅固的城牆和堅決的抵抗守住家園。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"총사대장님! 수도가 공격받고 있다는 전보입니다! 도와야 합니다!","JPN":"銃士隊長！　首都が攻撃を受けているという電報が入りました！　助けが必要です！","ENG":"Sir! We have received a report that the capital under attack! We must help!","TWN":"隊長！收到首都受到攻擊的電報！需要支援！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"아니. 열쇠를 확보한 이상, 우린 예정대로 떠난다.","JPN":"いや。鍵を確保した以上、予定通り出発する。","ENG":"No. As long as we've secured the Key, we follow through with our plan.","TWN":"不， 既然已經拿到鑰匙，我們就按計畫離開。"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"이대로는 시민들이 위험합니다! 돕게 해 주십시오, 총사대장님!","JPN":"このままでは市民が危険です！　助けに行くことを許可してください、銃士隊長！","ENG":"But the citizens are in danger! Permission to help them, sir!","TWN":"再這樣下去，市民們會有危險！請讓我們去幫忙，隊長！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"수도가 함락되면 나라를 지키는 데 써야 할 열쇠에 무슨 의미가 있습니까?!","JPN":"首都が陥落してしまったら、国を守るために使う鍵に何の意味があるのですか！？","ENG":"What use is the Key if there is be no kingdom left to protect, sir?!","TWN":"首都淪陷的話，用來保衛國家的鑰匙有什麼意義？！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"데이빗 부관님! 부관님의 가족 분들도 수도에 살고 계시지 않습니까!","JPN":"デイビッド副官！　副官のご家族も首都にお住まいではありませんか！","ENG":"Adjutant David, sir! You have family living in the capital, don't you?!","TWN":"大衛副隊長！副隊長的家人不是也住在首都嗎！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"수도 방위는 다른 모든 총사대들이 전력을 다하고 있다.","JPN":"首都の防衛は他のすべての銃士隊が全力を尽くしている。","ENG":"The capital is in safe hands with the other divisions.","TWN":"其他騎兵隊正在全力保護首都，"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"하지만 열쇠를 지키는 것은 우리 제 1 총사대에게만 주어진 사명이다.","JPN":"だが、鍵を守るのは我々第1銃士隊にのみ与えられた使命だ。","ENG":"But we, the 1st Division, are in charge of protecting the Key.","TWN":"但能夠保護鑰匙是卻只有我們第一騎兵隊。"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"그러니 지금은 총사대장님의 말씀을 따라라.","JPN":"だから今は銃士隊長に従え。","ENG":"So for now, follow the orders of the General Musketeer.","TWN":"所以還是現在聽隊長的吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"……큭. 알겠습니다.","JPN":"……くっ。かしこまりました。","ENG":"Krgh...! Understood.","TWN":"……咳，是。"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"전군, 열차에 탑승하라! 이대로 디어루트 외성까지 남하한다!","JPN":"全軍、列車に搭乗しろ！　このままディアルート外郭まで南下する！","ENG":"Men, board the train! We move south to Deer Root!","TWN":"全軍上列車！一起南下至迪魯特外城！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"총사대장님, 기관사의 말로는 종착역까지 3시간 가량 소요된다고 합니다.","JPN":"銃士隊長、機関士によりますと終着駅まで3時間くらいかかるそうです。","ENG":"Sir, the conductor estimates that we will arrive at the last stop in about 3 hours.","TWN":"隊長，火車駕駛說，到終點站需要3個小時左右。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"그래. 혹시 열차에 탄 민간인이 있던가?","JPN":"そうか。列車に乗っている民間人はいるか？","ENG":"Very well. Are there any civilians on board?","TWN":"好，火車上有平民嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"없습니다. 출발하기 전까지 지시대로 탑승을 통제했고, 차량 안도 전부 확인했습니다.","JPN":"いません。出発する前までご指示のとおり搭乗を統制し、車両内も全て確認しました。","ENG":"No, sir. We limited boarding prior to departure as instructed, and we also checked all the compartments on the train.","TWN":"沒有。出發前已按照指示控制其他人員搭乘，車內也全部確認完畢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"좋다. 계속 경계를 늦추지 말도록. 침식체가 열차를 습격할 가능성에 항상 대비해라.","JPN":"よし。そのまま警戒を怠るな。常に侵食体が列車を襲う場合に備えろ。","ENG":"Good. Don't let your guard down. Always be on the lookout for a possible C.O. attack on the train.","TWN":"很好，千萬不能鬆懈，侵蝕體很可能隨時襲擊火車。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"예.","JPN":"はっ。","ENG":"Yes, sir.","TWN":"好。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"다른 대원들에게도 전파해 두겠습니다.","JPN":"他の隊員にも伝えておきます。","ENG":"I'll pass the instruction along to the others.","TWN":"我會傳達給其他隊員的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"여기까지 오는 동안만 해도 도움이 필요한 많은 사람들을 지나쳤습니다.","JPN":"ここまで来る間だけでも助けを必要とする多くの人の前を通り過ぎました。","ENG":"We passed by many people who needed our help on our way over here.","TWN":"在我們抵達這裡的一路上，已經遇到許多需要協助的人。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"후회되지 않으십니까, 대장님.","JPN":"後悔してはいませんか、隊長。","ENG":"Don't you regret not helping them, General Musketeer?","TWN":"隊長，你不會後悔嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"……지금은 전시 상황이다. 희생을 감수할 수밖에 없어.","JPN":"……今は戦時だ。多少の犠牲は受け入れるしかない。","ENG":"...We are at war right now. We have no choice but to make sacrifices.","TWN":"……現在是戰爭時期，承受是無法避免的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"네. 저도 잘 알고 있습니다.","JPN":"はい。私もよくわかっております。","ENG":"Yes, I'm well aware of that.","TWN":"是，我也清楚。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"미안하다, 데이빗.","JPN":"すまないな、デイビッド。","ENG":"I'm sorry, David.","TWN":"對不起，大衛。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"수도를 등지고 떠난다는 건……. 자네에게나 다른 병사들에게나 힘든 선택이었겠지.","JPN":"首都に背を向けて発つというのは……君や他の兵士にとっても辛い選択だっただろう。","ENG":"I understand... that leaving the capital must have been a difficult choice for you and the others.","TWN":"離開首都這個決定……想必對你和其他士兵來說都不容易。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"상심하지 마십시오. 총사대장님은 필요한 선택을 하셨을 뿐입니다.","JPN":"気を落とさないでください。銃士隊長は必要な選択をなさっただけです。","ENG":"Don't be discouraged, sir. You're the one making the tough decisions.","TWN":"請不要難過，隊長只是做出必要的選擇。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"눈앞의 재해를 두고도 정반대의 길을 떠나야 한다는 사실은 힘들지만…","JPN":"災害を目の前にしながら、正反対の道を行かねばならないという事実は辛いですが……","ENG":"As you stated, it is difficult to leave in the opposite direction despite the impending disaster...","TWN":"雖然面對眼前的災難，卻要走一條截然相反的路，這件事很困難……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"나라를 지키기 위해 성유물이 필요하다는 건 다들 알고 있습니다.","JPN":"国を守るために聖遺物が必要だということは誰もが承知しております。","ENG":"However, I am also aware that the Holy Relic is required to protect this country.","TWN":"但大家都知道必須要保住聖遺物才能守住國家。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"그래. 그러니 설령 내 목숨을 바치는 한이 있더라도……","JPN":"そうか。だからこそ、たとえ私の命を捧げてでも……","ENG":"Yes. Even if it means I have to give up my life...","TWN":"你說的沒錯，因此就算要獻出我的生命……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"성유물만은 어떻게든 지켜낼 생각이다.","JPN":"聖遺物だけは守り通すつもりだ。","ENG":"I'll do everything I can to protect the Holy Relic.","TWN":"我會想盡辦法保住聖遺物。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"보고드립니다, 총사대장님. 터널이 무너져 더 이상 가는 건 어렵다고 합니다.","JPN":"ご報告いたします、銃士隊長。トンネルが崩壊し、これ以上先へは進めないとのことです。","ENG":"Reporting in, sir. The tunnel's collapsed, so we'll need another way to keep going south.","TWN":"報告隊長，據說前方隧道崩塌，無法再繼續前行。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"부관, 자네가 복구할 수 있겠나?","JPN":"副官、復旧できるか？","ENG":"Adjutant, do you think you can clear out the mess?","TWN":"副隊長，你有辦法修復嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"제대로 된 장비 없이는 어렵습니다. 잔해를 치우는 데만 일주일은 걸릴 겁니다.","JPN":"まともな装備もない状況なので難しいかと。残骸を片付けるだけでも一週間はかかるでしょう。","ENG":"Not without the proper tools, I’m afraid. It will take at least a week to even clear out the debris.","TWN":"現在沒有工具會有困難，光是清理殘骸可能就需要一週的時間。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"통신도 완전히 먹통입니다. 종착역과 무전이 되질 않습니다.","JPN":"通信も全滅です。終着駅との無線が繋がりません。","ENG":"Comms are down as well. We're not getting an answer from the final station.","TWN":"訊號也完全不通，無法與終點站聯繫。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"으음, 그 침식파라는 것의 영향인가.","JPN":"うーむ、その侵食波というものの影響だろうか。","ENG":"Hmm... Is it because of the Corruption ray?","TWN":"嗯嗯，是受到侵蝕波的影響嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"전군, 현 시간부로 열차에서 하차하라. 도보로 종착역까지 이동하겠다.","JPN":"全軍、現時刻をもって降車。終着駅まで徒歩で移動する。","ENG":"Men, from here on out we will walk to the final station.","TWN":"所有人聽著，立刻下車，步行到終點站。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"지금 이거… 눈이 내리고 있는 건가요?","JPN":"これ……雪でしょうか？","ENG":"Is it... snowing?","TWN":"這是…在下雪嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"그래. 한여름에 눈이라니 좋은 징조는 아니군.","JPN":"そのようだ。真夏に雪とは、あまりいい兆しではないな。","ENG":"Yes. Snow in mid-summer is never a good sign.","TWN":"沒錯，在盛夏下雪不是好兆頭。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"서두르지. 눈이 쌓이면 움직이기 곤란해.","JPN":"急ごう。雪が積もると動きにくくなる。","ENG":"Make haste! The snow will only slow us down.","TWN":"動作快，要是積雪會不好移動。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L16_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"총사대장님! 멀지 않은 곳에 연기가 보입니다!","JPN":"銃士隊長！　近くで煙が上がっています！","ENG":"Sir! I see smoke from not too far away from here!","TWN":"隊長！不遠處有煙！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"산불이라면 우회하면 될 일이다.","JPN":"山火事なら迂回すればいい。","ENG":"If it's a mountain fire we’ll go around it.","TWN":"若是野火，只需繞路而行。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"그게… 사람들이 살고 있는 마을 같은데, 단순한 화재는 아닌 것 같습니다.","JPN":"それが……人が住んでいる村と思われますが、単なる火事ではないようです。","ENG":"Well... It looks to be a village, and it does not appear to be a simple fire.","TWN":"那裡…似乎是有人居住的村莊，好像不是單純的森林大火。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"부관, 방금 감지기가 작동한 건가?","JPN":"副官、今のは感知機の作動音か？","ENG":"Adjutant, did the detector just react?","TWN":"副隊長，剛才感應器有反應嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"네. 침식파입니다.","JPN":"はい。侵食波です。","ENG":"Correct. It's a Corruption ray.","TWN":"是，有侵蝕波反應。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AIDE_BORDER_NULL_NULL","text":{"KOREA":"사람이 사는 마을이라면 침식체에게 공격 받고 있을 가능성이 높습니다. 우회할까요?","JPN":"人が住んでいる村なら、侵食体の攻撃を受けている可能性が高いです。迂回しますか？","ENG":"If there are people still living in the village, there is high probability they'll be attacked by C.O.s. Should we go around it?","TWN":"若是有人居住的村莊，那很可能是受到侵蝕體的攻擊，要繞路嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"아무리 명령이라지만 사람들이 죽어나가는 걸 무시해야 돼?","JPN":"いくら命令とはいえ、人々が死にゆくのを無視しなきゃいけないのか？","ENG":"I know we have our orders, but ignoring saving people who are about to die?","TWN":"就算是上頭下的命令，但現在可是人命關天欸？！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"쉿, 조용히 해. 총사대장님 입장도 있을 거 아냐.","JPN":"しっ、静かにしろ。銃士隊長も立場がおありだろう。","ENG":"Shh! Quiet. He must have his reasons.","TWN":"噓，你安靜點。隊長也有他的立場。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"마을의 규모는 어느 정도로 보이지?","JPN":"村の規模はどのくらいだ？","ENG":"How big is this village?","TWN":"村莊的規模看起來有多大？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOLDIER_BORDER_NULL_NULL","text":{"KOREA":"20여 가구 정도 되는 작은 마을입니다.","JPN":"約20世帯程の小さな村です。","ENG":"I see about 20 or so houses, sir.","TWN":"20多戶左右的小村莊。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"그런 규모의 마을이 공격받았다면…… 생존자가 남아 있을 가능성도 희박하겠군.","JPN":"その程度の村が攻撃を受けたとあれば……生存者が残っている可能性もごくわずかだろう。","ENG":"If a village of that size gets attacked... The chances of anyone surviving in that village is unlikely.","TWN":"那種規模的村莊若是受到攻擊的話……有人存活的可能性可說是微乎其微。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"우리에게는 남은 시간이 많지 않다. 다들, 서둘러 움직여라.","JPN":"我々に残された時間はあまりない。全員、急げ。","ENG":"We don’t have much time. Men, forward march!","TWN":"我們已經沒剩多少時間，大家加快腳步！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};